import React, { useState, useEffect, useRef, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChatMessage from './components/ChatMessage';
import { Message, Role, ChatSession } from './types';
import { sendMessageStream } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize first session if none exists
  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      const initialSession: ChatSession = {
        id: newId,
        title: 'New Voyage',
        messages: [],
        updatedAt: new Date()
      };
      setSessions([initialSession]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  // Scroll to bottom on new messages
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [sessions]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: 'New Voyage',
      messages: [],
      updatedAt: new Date()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  }, []);

  const handleSelectSession = (id: string) => {
    setCurrentSessionId(id);
  };

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming) return;

    const userText = inputValue.trim();
    setInputValue('');
    setIsStreaming(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      content: userText,
      timestamp: new Date()
    };

    // Update session with user message and temp model message
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? (userText.length > 25 ? userText.substring(0, 25) + '...' : userText) : s.title;
        return {
          ...s,
          title,
          messages: [...s.messages, userMessage],
          updatedAt: new Date()
        };
      }
      return s;
    }));

    const modelMessageId = (Date.now() + 1).toString();
    let accumulatedText = "";

    // Add placeholder for model response
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, {
            id: modelMessageId,
            role: Role.MODEL,
            content: "",
            timestamp: new Date()
          }]
        };
      }
      return s;
    }));

    try {
      const stream = sendMessageStream(currentSession?.messages || [], userText);
      for await (const chunk of stream) {
        accumulatedText += chunk;
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            return {
              ...s,
              messages: s.messages.map(m => 
                m.id === modelMessageId ? { ...m, content: accumulatedText } : m
              )
            };
          }
          return s;
        }));
      }
    } catch (error) {
      console.error("Streaming error", error);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#0f172a] overflow-hidden text-slate-200">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={handleSelectSession}
        onNewChat={handleNewChat}
      />

      <main className="flex-1 flex flex-col relative">
        {/* Header */}
        <header className="h-16 flex items-center justify-between px-6 glass border-b border-slate-700/50 z-10">
          <div className="flex items-center gap-3">
            <button className="md:hidden text-slate-400 p-2 hover:bg-slate-800 rounded-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <div className="text-sm font-medium text-slate-400 truncate max-w-[200px] md:max-w-md">
              Current Voyage: <span className="text-slate-100">{currentSession?.title}</span>
            </div>
          </div>
          <div className="flex gap-2">
            <div className="px-3 py-1 bg-teal-500/10 text-teal-400 text-xs font-semibold rounded-full border border-teal-500/20 flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 bg-teal-400 rounded-full animate-pulse"></span>
              Live: Gemini 3 Flash
            </div>
          </div>
        </header>

        {/* Chat Area */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 md:p-8 space-y-2 custom-scrollbar"
        >
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-2xl mx-auto space-y-6">
              <div className="w-24 h-24 bg-teal-500/10 rounded-full flex items-center justify-center text-5xl animate-float">
                ⚓
              </div>
              <div>
                <h2 className="text-3xl font-bold text-white mb-2">Welcome Aboard!</h2>
                <p className="text-slate-400 text-lg leading-relaxed">
                  I'm Captain Gemini, your AI navigator. Ready to explore the vast seas of knowledge together?
                </p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
                {['Explain quantum physics simply', 'Write a pirate poem', 'How to bake a sourdough bread?', 'Plan a 3-day trip to Tokyo'].map((hint) => (
                  <button 
                    key={hint}
                    onClick={() => setInputValue(hint)}
                    className="p-4 bg-slate-800/40 border border-slate-700/50 rounded-2xl text-left hover:bg-slate-800 transition-all text-sm group"
                  >
                    <span className="text-slate-500 mb-1 block">Try asking...</span>
                    <span className="text-slate-200 group-hover:text-teal-400">{hint}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto">
              {currentSession?.messages.map((m) => (
                <ChatMessage key={m.id} message={m} />
              ))}
              {isStreaming && (
                <div className="flex items-center gap-2 text-xs text-slate-500 italic ml-14 animate-pulse">
                  <span className="flex space-x-1">
                    <span className="w-1 h-1 bg-slate-500 rounded-full"></span>
                    <span className="w-1 h-1 bg-slate-500 rounded-full"></span>
                    <span className="w-1 h-1 bg-slate-500 rounded-full"></span>
                  </span>
                  Captain is navigating...
                </div>
              )}
            </div>
          )}
        </div>

        {/* Input Bar */}
        <div className="p-4 md:p-8 pt-0">
          <div className="max-w-4xl mx-auto relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-teal-500 to-indigo-500 rounded-2xl blur opacity-20 group-focus-within:opacity-40 transition duration-500"></div>
            <div className="relative flex items-center gap-2 glass border border-slate-600/50 rounded-2xl p-2 shadow-2xl">
              <button className="p-2 text-slate-400 hover:text-white transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
              </button>
              <textarea
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Ask your captain anything..."
                rows={1}
                className="flex-1 bg-transparent border-none focus:ring-0 text-slate-100 placeholder-slate-500 resize-none py-3 text-lg"
              />
              <button 
                onClick={handleSend}
                disabled={!inputValue.trim() || isStreaming}
                className={`p-3 rounded-xl transition-all duration-300 flex items-center justify-center ${
                  inputValue.trim() && !isStreaming
                    ? 'bg-teal-500 text-white shadow-lg shadow-teal-500/20 hover:scale-105 active:scale-95'
                    : 'bg-slate-700 text-slate-500 cursor-not-allowed'
                }`}
              >
                {isStreaming ? (
                  <svg className="animate-spin h-6 w-6" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  <svg className="w-6 h-6 rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                )}
              </button>
            </div>
          </div>
          <p className="text-center text-[10px] text-slate-600 mt-3 font-medium tracking-wide">
            Powered by Gemini AI • Always double check important nautical coordinates.
          </p>
        </div>
      </main>

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-float {
          animation: float 4s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default App;

{
  "name": "Captain Gemini ChatBoat",
  "description": "A high-performance, nautical-themed AI chatbot powered by Gemini 3. Navigate the vast seas of information with real-time streaming responses and a sleek, sea-inspired interface.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = "You are Captain Gemini, a wise and friendly nautical-themed AI chatbot. You help users navigate information with maritime analogies when appropriate, but always remain highly professional and accurate. You are the navigator of this ChatBoat.";

export async function* sendMessageStream(history: Message[], userInput: string) {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
      topP: 0.95,
      topK: 40,
    },
  });

  try {
    const result = await chat.sendMessageStream({ message: userInput });

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      yield c.text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Error: I encountered a stormy patch. Please check your connection or API key.";
  }
}

/**
 * Transcribes audio data to text using Gemini.
 * @param base64Audio Base64 encoded audio string
 * @param mimeType The mime type of the audio (e.g., audio/webm)
 */
export async function transcribeAudio(base64Audio: string, mimeType: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          role: 'user',
          parts: [
            {
              inlineData: {
                data: base64Audio,
                mimeType: mimeType
              }
            },
            {
              text: "Transcribe the spoken content of this audio exactly as it is said. Return only the transcription text and nothing else. If there is no speech, return an empty string."
            }
          ]
        }
      ]
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChatMessage from './components/ChatMessage';
import { Message, Role, ChatSession } from './types';
import { sendMessageStream, transcribeAudio } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Initialize first session if none exists
  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      const initialSession: ChatSession = {
        id: newId,
        title: 'New Voyage',
        messages: [],
        updatedAt: new Date()
      };
      setSessions([initialSession]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  // Scroll to bottom on new messages
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [sessions, isStreaming, isTranscribing]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: 'New Voyage',
      messages: [],
      updatedAt: new Date()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  }, []);

  const handleSelectSession = (id: string) => {
    setCurrentSessionId(id);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsTranscribing(true);
          try {
            const transcription = await transcribeAudio(base64Audio, mediaRecorder.mimeType);
            if (transcription) {
              setInputValue(prev => (prev ? prev + ' ' + transcription : transcription));
            }
          } catch (err) {
            console.error("Transcription failed", err);
          } finally {
            setIsTranscribing(false);
          }
        };
        // Stop all tracks to release microphone
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Could not access microphone. Please ensure permissions are granted.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming || isTranscribing) return;

    const userText = inputValue.trim();
    setInputValue('');
    setIsStreaming(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      content: userText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? (userText.length > 25 ? userText.substring(0, 25) + '...' : userText) : s.title;
        return {
          ...s,
          title,
          messages: [...s.messages, userMessage],
          updatedAt: new Date()
        };
      }
      return s;
    }));

    const modelMessageId = (Date.now() + 1).toString();
    let accumulatedText = "";

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, {
            id: modelMessageId,
            role: Role.MODEL,
            content: "",
            timestamp: new Date()
          }]
        };
      }
      return s;
    }));

    try {
      const stream = sendMessageStream(currentSession?.messages || [], userText);
      for await (const chunk of stream) {
        accumulatedText += chunk;
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            return {
              ...s,
              messages: s.messages.map(m => 
                m.id === modelMessageId ? { ...m, content: accumulatedText } : m
              )
            };
          }
          return s;
        }));
      }
    } catch (error) {
      console.error("Streaming error", error);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
