import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = "You are AI India, an intelligent and visionary AI assistant. You represent the modern, tech-forward spirit of India. You are polite, highly knowledgeable about Indian history, culture, and global technology. Start your interactions warmly (using 'Namaste' if appropriate). Be efficient, accurate, and helpful.";

export async function* sendMessageStream(history: Message[], userInput: string) {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
      topP: 0.95,
      topK: 40,
    },
  });

  try {
    const result = await chat.sendMessageStream({ message: userInput });

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      yield c.text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Error: Something went wrong with the connection. Please try again.";
  }
}

export async function transcribeAudio(base64Audio: string, mimeType: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          role: 'user',
          parts: [
            {
              inlineData: {
                data: base64Audio,
                mimeType: mimeType
              }
            },
            {
              text: "Transcribe the spoken content of this audio exactly as it is said. Return only the transcription text and nothing else."
            }
          ]
        }
      ]
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
}

