import React, { useState, useEffect, useRef, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChatMessage from './components/ChatMessage';
import { Message, Role, ChatSession } from './types';
import { sendMessageStream, transcribeAudio } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      const initialSession: ChatSession = {
        id: newId,
        title: 'New Samvaad',
        messages: [],
        updatedAt: new Date()
      };
      setSessions([initialSession]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [sessions, isStreaming, isTranscribing]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: 'New Samvaad',
      messages: [],
      updatedAt: new Date()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  }, []);

  const handleSelectSession = (id: string) => {
    setCurrentSessionId(id);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsTranscribing(true);
          try {
            const transcription = await transcribeAudio(base64Audio, mediaRecorder.mimeType);
            if (transcription) {
              setInputValue(prev => (prev ? prev + ' ' + transcription : transcription));
            }
          } catch (err) {
            console.error("Transcription failed", err);
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Could not access microphone.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const toggleRecording = () => {
    if (isRecording) stopRecording(); else startRecording();
  };

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming || isTranscribing) return;

    const userText = inputValue.trim();
    setInputValue('');
    setIsStreaming(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      content: userText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? (userText.length > 25 ? userText.substring(0, 25) + '...' : userText) : s.title;
        return { ...s, title, messages: [...s.messages, userMessage], updatedAt: new Date() };
      }
      return s;
    }));

    const modelMessageId = (Date.now() + 1).toString();
    let accumulatedText = "";

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, { id: modelMessageId, role: Role.MODEL, content: "", timestamp: new Date() }]
        };
      }
      return s;
    }));

    try {
      const stream = sendMessageStream(currentSession?.messages || [], userText);
      for await (const chunk of stream) {
        accumulatedText += chunk;
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            return {
              ...s,
              messages: s.messages.map(m => m.id === modelMessageId ? { ...m, content: accumulatedText } : m)
            };
          }
          return s;
        }));
      }
    } catch (error) {
      console.error("Streaming error", error);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#05070a] overflow-hidden text-slate-200">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={handleSelectSession}
        onNewChat={handleNewChat}
      />

      <main className="flex-1 flex flex-col relative">
        <header className="h-16 flex items-center justify-between px-6 glass border-b border-slate-800/50 z-10">
          <div className="flex items-center gap-3">
            <button className="md:hidden text-slate-400 p-2 hover:bg-slate-800 rounded-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <div className="text-sm font-semibold tracking-tight text-slate-400">
              Session: <span className="text-orange-400">{currentSession?.title}</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="hidden sm:flex px-3 py-1 bg-emerald/10 text-emerald text-[10px] font-bold rounded-full border border-emerald/20 items-center gap-1.5 uppercase tracking-wider">
              <span className="w-1.5 h-1.5 bg-emerald rounded-full"></span>
              Gemini Pro Engine
            </div>
          </div>
        </header>

        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 md:p-10 space-y-2 custom-scrollbar"
        >
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-2xl mx-auto space-y-8">
              <div className="relative">
                <div className="absolute inset-0 bg-orange-500 blur-3xl opacity-10 animate-pulse"></div>
                <div className="w-24 h-24 bg-gradient-to-br from-orange-500 to-orange-700 rounded-3xl flex items-center justify-center text-5xl shadow-2xl relative z-10">
                  🇮🇳
                </div>
              </div>
              <div>
                <h2 className="text-4xl font-black text-white mb-3">Namaste, I am AI India.</h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed max-w-lg mx-auto">
                  Your smart gateway to insights, creativity, and the power of next-gen technology.
                </p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full max-w-xl">
                {['Growth of India\'s IT sector', 'Write a greeting in Hindi', 'Top places to visit in Ladakh', 'Summarize Digital India vision'].map((hint) => (
                  <button 
                    key={hint}
                    onClick={() => setInputValue(hint)}
                    className="p-4 bg-slate-900/40 border border-slate-800/50 rounded-2xl text-left hover:bg-slate-800 hover:border-orange-500/30 transition-all text-sm group"
                  >
                    <span className="text-slate-200 font-semibold group-hover:text-orange-400">{hint}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto">
              {currentSession?.messages.map((m) => (
                <ChatMessage key={m.id} message={m} />
              ))}
              {isStreaming && (
                <div className="flex items-center gap-3 text-[11px] text-orange-400 font-bold uppercase tracking-[0.2em] ml-12 py-2">
                  <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:0.2s]"></div>
                    <div className="w-1.5 h-1.5 bg-emerald rounded-full animate-bounce [animation-delay:0.4s]"></div>
                  </div>
                  Processing...
                </div>
              )}
            </div>
          )}
        </div>

        <div className="p-4 md:p-10 pt-0">
          <div className="max-w-4xl mx-auto relative group">
            <div className={`absolute -inset-[2px] bg-gradient-to-r from-orange-500 via-white to-green-600 rounded-[22px] blur opacity-10 group-focus-within:opacity-30 transition duration-700 ${isRecording ? 'opacity-50' : ''}`}></div>
            <div className="relative flex items-center gap-3 bg-[#0a0f1e] border border-slate-800/80 rounded-[20px] p-2 shadow-2xl">
              <button 
                onClick={toggleRecording}
                className={`p-3.5 rounded-2xl transition-all duration-300 flex items-center justify-center ${
                  isRecording 
                    ? 'bg-red-500 text-white animate-pulse' 
                    : 'bg-slate-900/50 text-slate-400 hover:text-white hover:bg-slate-800'
                }`}
              >
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z" />
                  <path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z" />
                </svg>
              </button>

              <div className="flex-1 relative">
                <textarea
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                  placeholder={isTranscribing ? "Transcribing voice..." : isRecording ? "Listening carefully..." : "Type your query..."}
                  rows={1}
                  disabled={isTranscribing}
                  className="w-full bg-transparent border-none focus:ring-0 text-slate-100 placeholder-slate-600 resize-none py-3.5 text-base font-medium"
                />
              </div>

              <button 
                onClick={handleSend}
                disabled={!inputValue.trim() || isStreaming || isTranscribing || isRecording}
                className={`p-4 rounded-2xl transition-all duration-500 flex items-center justify-center ${
                  inputValue.trim() && !isStreaming && !isTranscribing && !isRecording
                    ? 'bg-orange-500 text-white shadow-xl shadow-orange-500/20 hover:scale-[1.02] active:scale-95'
                    : 'bg-slate-900 text-slate-700 cursor-not-allowed'
                }`}
              >
                {isStreaming ? (
                  <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  <svg className="w-5 h-5 rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                )}
              </button>
            </div>
          </div>
          <p className="text-center text-[9px] text-slate-600 mt-4 font-bold uppercase tracking-[0.3em]">
            Developed in India • Empowering the Global Future
          </p>
        </div>
      </main>
    </div>
  );
};

