import React, { useState, useEffect, useRef, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChatMessage from './components/ChatMessage';
import { Message, Role, ChatSession } from './types';
import { sendMessageStream, transcribeAudio } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isOnline, setIsOnline] = useState(true);

  const scrollRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Monitor connectivity
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      const initialSession: ChatSession = {
        id: newId,
        title: 'Initial Samvaad',
        messages: [],
        updatedAt: new Date()
      };
      setSessions([initialSession]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [sessions, isStreaming, isTranscribing]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: 'New Samvaad',
      messages: [],
      updatedAt: new Date()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  }, []);

  const handleSelectSession = (id: string) => {
    setCurrentSessionId(id);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsTranscribing(true);
          try {
            const transcription = await transcribeAudio(base64Audio, mediaRecorder.mimeType);
            if (transcription) {
              setInputValue(prev => (prev ? prev + ' ' + transcription : transcription));
            }
          } catch (err) {
            console.error("Transcription failed", err);
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Microphone access denied:", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const toggleRecording = () => isRecording ? stopRecording() : startRecording();

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming || isTranscribing || !isOnline) return;

    const userText = inputValue.trim();
    setInputValue('');
    setIsStreaming(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      content: userText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const title = s.messages.length === 0 ? (userText.length > 25 ? userText.substring(0, 25) + '...' : userText) : s.title;
        return { ...s, title, messages: [...s.messages, userMessage], updatedAt: new Date() };
      }
      return s;
    }));

    const modelMessageId = (Date.now() + 1).toString();
    let accumulatedText = "";

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, { id: modelMessageId, role: Role.MODEL, content: "", timestamp: new Date() }]
        };
      }
      return s;
    }));

    try {
      const stream = sendMessageStream(currentSession?.messages || [], userText);
      for await (const chunk of stream) {
        accumulatedText += chunk;
        setSessions(prev => prev.map(s => {
          if (s.id === currentSessionId) {
            return {
              ...s,
              messages: s.messages.map(m => m.id === modelMessageId ? { ...m, content: accumulatedText } : m)
            };
          }
          return s;
        }));
      }
    } catch (error) {
      console.error("Streaming error", error);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#020408] overflow-hidden text-slate-100 selection:bg-orange-500/20">
      <Sidebar 
        sessions={sessions} 
        currentSessionId={currentSessionId}
        onSelectSession={handleSelectSession}
        onNewChat={handleNewChat}
      />

      <main className="flex-1 flex flex-col relative">
        {/* Deployed Header */}
        <header className="h-20 flex items-center justify-between px-8 glass border-b border-white/5 z-20">
          <div className="flex items-center gap-4">
            <button className="md:hidden text-slate-400 p-2 hover:bg-white/10 rounded-xl transition-colors">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-orange-500">Live Production</span>
              <span className="text-sm font-bold tracking-tight text-white/90">
                {currentSession?.title}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden lg:flex items-center gap-3">
                <div className="flex flex-col items-end">
                  <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">System Load</span>
                  <span className="text-[11px] font-mono text-emerald-400">Normal (0.12ms)</span>
                </div>
                <div className="w-[1px] h-8 bg-white/5"></div>
             </div>

             <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-[10px] font-bold uppercase tracking-widest transition-all duration-500
                ${isOnline 
                  ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' 
                  : 'bg-red-500/10 text-red-400 border-red-500/20 animate-pulse'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.5)]' : 'bg-red-400'}`}></span>
                {isOnline ? 'Stable' : 'Offline'}
             </div>
          </div>
        </header>

        {/* Messaging Core */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-6 md:p-12 space-y-4 custom-scrollbar"
        >
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-3xl mx-auto py-10">
              <div className="relative mb-10 group">
                <div className="absolute inset-0 bg-gradient-to-tr from-orange-500 via-white to-green-600 rounded-[35px] blur-3xl opacity-20 group-hover:opacity-40 transition-opacity duration-1000"></div>
                <div className="w-32 h-32 bg-[#05070a] rounded-[35px] flex items-center justify-center text-6xl shadow-2xl relative z-10 border border-white/5 group-hover:border-orange-500/30 transition-all duration-500 transform group-hover:rotate-6">
                  🇮🇳
                </div>
              </div>

              <div className="space-y-4">
                <h2 className="text-5xl font-black tracking-tighter text-white">
                  Namaste <span className="text-gradient-in">India</span>
                </h2>
                <p className="text-slate-400 text-lg font-medium max-w-lg mx-auto leading-relaxed">
                  Your flagship AI companion, built for precision, speed, and meaningful Samvaads.
                </p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full mt-12">
                {[
                  { label: "Visionary", text: "What is India's role in Global AI?" },
                  { label: "Creative", text: "Compose a Ghazal about modern Delhi." },
                  { label: "Technical", text: "Explain UPI architecture simply." },
                  { label: "Cultural", text: "Importance of the Ashoka Chakra." }
                ].map((hint, i) => (
                  <button 
                    key={i}
                    onClick={() => setInputValue(hint.text)}
                    className="p-5 glass border border-white/5 rounded-3xl text-left hover:bg-white/5 hover:border-orange-500/30 transition-all group flex flex-col gap-1"
                  >
                    <span className="text-[10px] font-black uppercase tracking-widest text-orange-500/60">{hint.label}</span>
                    <span className="text-slate-200 font-bold group-hover:text-white">{hint.text}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="max-w-5xl mx-auto w-full">
              {currentSession?.messages.map((m) => (
                <ChatMessage key={m.id} message={m} />
              ))}
              {isStreaming && (
                <div className="flex items-center gap-4 text-[10px] text-orange-400 font-black uppercase tracking-[0.25em] ml-14 py-4">
                  <div className="flex gap-1.5">
                    <div className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-bounce"></div>
                  </div>
                  Synthesizing Response
                </div>
              )}
            </div>
          )}
        </div>

        {/* Advanced Input Terminal */}
        <div className="p-6 md:p-12 pt-0">
          <div className="max-w-5xl mx-auto relative group">
            <div className={`absolute -inset-[1px] bg-gradient-to-r from-orange-500 via-white to-green-600 rounded-[28px] blur-md opacity-10 group-focus-within:opacity-25 transition duration-700 ${isRecording ? 'opacity-40' : ''}`}></div>

            <div className="relative flex items-center gap-4 glass bg-[#05070a]/80 rounded-[26px] p-2.5 shadow-2xl border border-white/5 group-focus-within:border-white/10 transition-all">

              <button 
                onClick={toggleRecording}
                disabled={isStreaming || isTranscribing}
                className={`p-4 rounded-2xl transition-all duration-500 flex items-center justify-center ${
                  isRecording 
                    ? 'bg-red-500 text-white shadow-[0_0_20px_rgba(239,68,68,0.4)] animate-pulse' 
                    : 'bg-white/5 text-slate-400 hover:text-white hover:bg-white/10'
                }`}
              >
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z" />
                  <path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z" />
                </svg>
              </button>

              <div className="flex-1 relative">
                <textarea
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                  placeholder={isTranscribing ? "Finalizing transcription..." : isRecording ? "Transmitting audio signal..." : "Message AI India..."}
                  rows={1}
                  disabled={isTranscribing}
                  className="w-full bg-transparent border-none focus:ring-0 text-white placeholder-slate-600 resize-none py-4 text-[17px] font-medium leading-tight"
                />
              </div>

              <button 
                onClick={handleSend}
                disabled={!inputValue.trim() || isStreaming || isTranscribing || isRecording || !isOnline}
                className={`p-4.5 w-14 h-14 rounded-2xl transition-all duration-500 flex items-center justify-center ${
                  inputValue.trim() && !isStreaming && !isTranscribing && !isRecording && isOnline
                    ? 'bg-orange-500 text-white shadow-xl shadow-orange-500/30 hover:scale-[1.04] active:scale-95'
                    : 'bg-white/5 text-slate-700 cursor-not-allowed'
                }`}
              >
                {isStreaming ? (
                  <svg className="animate-spin h-6 w-6" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  <svg className="w-6 h-6 rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                  </svg>
                )}
              </button>
            </div>
          </div>

          <div className="flex items-center justify-center gap-6 mt-6 opacity-30">
            <span className="text-[9px] font-black uppercase tracking-[0.4em]">Engine: Gemini 3-Flash</span>
