export enum Role {
  USER = 'user',
  MODEL = 'model',
  SYSTEM = 'system'
}

export enum MessageType {
  TEXT = 'text',
  IMAGE = 'image',
  VIDEO = 'video',
  CODE = 'code'
}

export interface Message {
  id: string;
  role: Role;
  type: MessageType;
  content: string; // text or base64/url for media
  timestamp: Date;
  metadata?: {
    prompt?: string;
    status?: 'pending' | 'completed' | 'failed';
    thumbnail?: string;
  };
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: Date;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = "You are AI India, an intelligent and visionary AI assistant. You represent the modern, tech-forward spirit of India. You are polite, highly knowledgeable about Indian history, culture, and global technology. Start your interactions warmly (using 'Namaste' if appropriate). Be efficient, accurate, and helpful.";

export async function* sendMessageStream(history: Message[], userInput: string) {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
      topP: 0.95,
      topK: 40,
    },
  });

  try {
    const result = await chat.sendMessageStream({ message: userInput });

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      yield c.text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Error: Something went wrong with the connection. Please try again.";
  }
}

export async function generateImage(prompt: string): Promise<string> {
  // Use gemini-2.5-flash-image for generation
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data returned from API.");
}

export async function generateVideo(prompt: string, onProgress: (msg: string) => void): Promise<string> {
  // Using Veo requires a fresh instance to ensure correct API key from dialog
  const veoAi = new GoogleGenAI({ apiKey: process.env.API_KEY });

  onProgress("Initializing high-performance video synthesis...");
  let operation = await veoAi.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  onProgress("Rendering cinematic frames... this may take a moment.");
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await veoAi.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  onProgress("Finalizing export...");
  const fetchResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await fetchResponse.blob();
  return URL.createObjectURL(blob);
}

export async function transcribeAudio(base64Audio: string, mimeType: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          role: 'user',
          parts: [
            {
              inlineData: {
                data: base64Audio,
                mimeType: mimeType
              }
            },
            {
              text: "Transcribe the spoken content of this audio exactly as it is said. Return only the transcription text and nothing else."
            }
          ]
        }
      ]
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
}

import React, { useState } from 'react';
import { Message, Role, MessageType } from '../types';

interface ChatMessageProps {
  message: Message;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ message }) => {
  const isUser = message.role === Role.USER;
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const renderContent = () => {
    switch (message.type) {
      case MessageType.IMAGE:
        return (
          <div className="space-y-3">
             <img 
               src={message.content} 
               alt="AI Generated" 
               className="rounded-2xl w-full max-w-sm shadow-2xl border border-white/10 hover:scale-[1.02] transition-transform duration-500 cursor-zoom-in"
             />
             <p className="text-[11px] text-slate-400 italic">Prompt: {message.metadata?.prompt}</p>
          </div>
        );
      case MessageType.VIDEO:
        return (
          <div className="space-y-3">
            <video 
              src={message.content} 
              controls 
              className="rounded-2xl w-full max-w-md shadow-2xl border border-white/10"
            />
            <p className="text-[11px] text-slate-400 italic">Prompt: {message.metadata?.prompt}</p>
          </div>
        );
      case MessageType.CODE:
        return (
          <div className="font-mono text-sm bg-black/40 p-4 rounded-xl border border-white/5 overflow-x-auto selection:bg-blue-500/30">
            <pre>{message.content}</pre>
          </div>
        );
      default:
        return (
          <div className="whitespace-pre-wrap break-words leading-relaxed text-[15px] selection:bg-orange-500/30">
            {message.content || (
              <div className="flex space-x-2 py-2">
                <div className="w-2 h-2 bg-orange-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                <div className="w-2 h-2 bg-white rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce"></div>
              </div>
            )}
          </div>
        );
    }
  };

  return (
    <div className={`flex w-full mb-8 group ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div className={`flex max-w-[85%] md:max-w-[80%] ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>
        {/* Avatar */}
        <div className={`flex-shrink-0 h-10 w-10 rounded-2xl flex items-center justify-center text-xl shadow-xl transition-transform duration-300 group-hover:scale-110
          ${isUser ? 'bg-[#000080] ml-4' : 'bg-gradient-to-br from-[#FF9933] to-[#FFCC33] mr-4'}`}>
          {isUser ? '👤' : '🇮🇳'}
        </div>

        {/* Message Bubble */}
        <div className="relative flex flex-col items-start space-y-1">
          <div className={`flex items-center gap-2 mb-1 px-1 ${isUser ? 'flex-row-reverse w-full' : ''}`}>
             <span className={`text-[11px] font-bold uppercase tracking-[0.15em] opacity-40 ${isUser ? 'text-blue-400' : 'text-orange-400'}`}>
              {isUser ? 'User' : 'AI India Multi-Modal'}
            </span>
            <span className="text-[10px] opacity-20 font-mono">
              {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          </div>

          <div className={`relative px-5 py-4 rounded-3xl shadow-lg border transition-all duration-300
            ${isUser 
              ? 'bg-[#0a0f1e]/80 rounded-tr-none text-slate-100 border-white/5 group-hover:border-blue-500/30' 
              : 'glass rounded-tl-none text-slate-100 border-white/5 group-hover:border-orange-500/30'}`}>

            {renderContent()}

            {/* Action Buttons */}
            {!isUser && message.type === MessageType.TEXT && message.content && (
              <button 
                onClick={copyToClipboard}
                className="absolute -bottom-6 right-0 opacity-0 group-hover:opacity-100 transition-all duration-200 text-[10px] font-bold text-slate-500 hover:text-orange-400 flex items-center gap-1 uppercase tracking-wider"
              >
                {copied ? 'Copied' : 'Copy'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

