  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    const mesh = document.getElementById('mesh');
    if (mesh) mesh.className = `bg-mesh theme-${themes[currentThemeIndex].id}`;
  }, [currentThemeIndex]);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      const initialSession: ChatSession = {
        id: newId,
        title: 'Initial Samvaad',
        messages: [],
        updatedAt: new Date()
      };
      setSessions([initialSession]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [sessions, isStreaming, isTranscribing, videoStatus]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    const newSession: ChatSession = { id: newId, title: 'New Samvaad', messages: [], updatedAt: new Date() };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  }, []);

  const handleSelectSession = (id: string) => setCurrentSessionId(id);
  const cycleTheme = () => setCurrentThemeIndex((prev) => (prev + 1) % themes.length);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsTranscribing(true);
          try {
            const transcription = await transcribeAudio(base64Audio, mediaRecorder.mimeType);
            if (transcription) setInputValue(prev => prev ? prev + ' ' + transcription : transcription);
          } catch (err) { console.error(err); } finally { setIsTranscribing(false); }
        };
        stream.getTracks().forEach(t => t.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) { console.error(err); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const addMessage = (role: Role, type: MessageType, content: string, metadata?: any) => {
    const newMessage: Message = { id: Date.now().toString(), role, type, content, timestamp: new Date(), metadata };
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, newMessage], updatedAt: new Date() };
      }
      return s;
    }));
    return newMessage.id;
  };

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming || isTranscribing || !isOnline) return;

    const userText = inputValue.trim();
    setInputValue('');
    addMessage(Role.USER, currentTool, userText);

    if (currentTool === MessageType.TEXT || currentTool === MessageType.CODE) {
      setIsStreaming(true);
      const modelMessageId = addMessage(Role.MODEL, currentTool, "");
      let accumulatedText = "";
      try {
        const stream = sendMessageStream(currentSession?.messages || [], userText);
        for await (const chunk of stream) {
          accumulatedText += chunk;
          setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
              return { ...s, messages: s.messages.map(m => m.id === modelMessageId ? { ...m, content: accumulatedText } : m) };
            }
            return s;
          }));
        }
      } catch (e) { console.error(e); } finally { setIsStreaming(false); }
    } 
    else if (currentTool === MessageType.IMAGE) {
      setIsStreaming(true);
      try {
        const imageUrl = await generateImage(userText);
        addMessage(Role.MODEL, MessageType.IMAGE, imageUrl, { prompt: userText });
      } catch (e) {
        addMessage(Role.MODEL, MessageType.TEXT, "Apologies, the photo generator encountered a storm.");
      } finally { setIsStreaming(false); }
    } 
    else if (currentTool === MessageType.VIDEO) {
      // Veo check
      if (!(await window.aistudio.hasSelectedApiKey())) {
        await window.aistudio.openSelectKey();
      }
      setIsStreaming(true);
      try {
        const videoUrl = await generateVideo(userText, setVideoStatus);
        addMessage(Role.MODEL, MessageType.VIDEO, videoUrl, { prompt: userText });
      } catch (e) {
        addMessage(Role.MODEL, MessageType.TEXT, "Video generation failed. Please check your billing/API settings.");
      } finally { 
        setIsStreaming(false); 
        setVideoStatus(null);
      }
    }
  };

  return (
    <div className="flex h-screen w-full bg-transparent overflow-hidden text-slate-100 selection:bg-orange-500/20">
      <Sidebar sessions={sessions} currentSessionId={currentSessionId} onSelectSession={handleSelectSession} onNewChat={handleNewChat} />

      <main className="flex-1 flex flex-col relative">
        <header className="h-20 flex items-center justify-between px-8 glass border-b border-white/5 z-20">
          <div className="flex items-center gap-4">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-orange-500">Multimodal Nexus</span>
              <span className="text-sm font-bold tracking-tight text-white/90">{currentSession?.title}</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <button onClick={cycleTheme} className="flex items-center gap-2 px-3 py-1.5 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-[11px] font-bold">
               <span className="text-sm">{themes[currentThemeIndex].icon}</span>
               <span className="hidden sm:inline">{themes[currentThemeIndex].name}</span>
             </button>

             <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-[10px] font-bold uppercase tracking-widest ${isOnline ? 'text-emerald-400 border-emerald-500/20' : 'text-red-400 border-red-500/20'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-400' : 'bg-red-400'}`}></span>
                {isOnline ? 'Stable' : 'Offline'}
             </div>
          </div>
        </header>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-12 space-y-4 custom-scrollbar">
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-3xl mx-auto py-10">
              <h2 className="text-5xl font-black tracking-tighter text-white mb-4">Namaste <span className="text-gradient-in">India</span></h2>
              <p className="text-slate-400 text-lg mb-10">Generate photos, high-quality videos, or build apps with a single prompt.</p>
              <div className="grid grid-cols-2 gap-4 w-full max-w-lg">
                {tools.map(t => (
                  <button key={t.id} onClick={() => setCurrentTool(t.id)} className={`p-6 rounded-3xl border transition-all flex flex-col items-center gap-2 ${currentTool === t.id ? 'bg-orange-500/10 border-orange-500/50' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                    <span className="text-3xl">{t.icon}</span>
                    <span className="text-xs font-bold uppercase tracking-widest">{t.name}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="max-w-5xl mx-auto w-full">
              {currentSession?.messages.map((m) => <ChatMessage key={m.id} message={m} />)}
              {(isStreaming || videoStatus) && (
                <div className="flex items-center gap-4 text-[10px] text-orange-400 font-black uppercase tracking-[0.25em] ml-14 py-4 animate-pulse">
                  <div className="flex gap-1.5">
                    <div className="w-1.5 h-1.5 bg-orange-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-white rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                  </div>
                  {videoStatus || "Synthesizing..."}
                </div>
              )}
            </div>
          )}
        </div>

        <div className="p-6 md:p-12 pt-0">
          <div className="max-w-5xl mx-auto">
            {/* Tool Toggle Row */}
            <div className="flex gap-2 mb-4">
              {tools.map(t => (
                <button 
                  key={t.id} 
                  onClick={() => setCurrentTool(t.id)} 
                  className={`px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all ${currentTool === t.id ? 'bg-orange-500 text-white shadow-lg shadow-orange-500/20' : 'bg-white/5 text-slate-500 hover:text-slate-300'}`}
                >
                  {t.icon} {t.name}
                </button>
              ))}
            </div>

            <div className="relative group">
              <div className={`absolute -inset-[1px] bg-gradient-to-r from-orange-500 via-white to-green-600 rounded-[28px] blur-md opacity-10 group-focus-within:opacity-25 transition duration-700 ${isRecording ? 'opacity-40' : ''}`}></div>
              <div className="relative flex items-center gap-4 glass bg-[#05070a]/80 rounded-[26px] p-2.5 shadow-2xl border border-white/5">
                <button onClick={toggleRecording} disabled={isStreaming} className={`p-4 rounded-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-white/5 text-slate-400'}`}>
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                </button>
                <textarea
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
                  placeholder={currentTool === MessageType.IMAGE ? "Describe the photo to generate..." : currentTool === MessageType.VIDEO ? "Describe the video scene..." : "Type your query..."}
                  rows={1}
                  disabled={isTranscribing}
                  className="flex-1 bg-transparent border-none focus:ring-0 text-white placeholder-slate-600 resize-none py-4 text-[17px]"
                />
                <button onClick={handleSend} disabled={!inputValue.trim() || isStreaming || !isOnline} className={`p-4.5 w-14 h-14 rounded-2xl transition-all flex items-center justify-center ${inputValue.trim() && !isStreaming ? 'bg-orange-500 text-white' : 'bg-white/5 text-slate-700'}`}>
                  {isStreaming ? <div className="animate-spin h-5 w-5 border-2 border-white/20 border-t-white rounded-full"></div> : <svg className="w-6 h-6 rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"/></svg>}
                </button>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role } from "../types";

const SYSTEM_INSTRUCTION = "You are AI India, an intelligent and visionary AI assistant. You represent the modern, tech-forward spirit of India. You are polite, highly knowledgeable about Indian history, culture, and global technology. Start your interactions warmly (using 'Namaste' if appropriate). Be efficient, accurate, and helpful.";

// Use gemini-3-pro-preview for complex tasks like coding and gemini-3-flash-preview for general text
export async function* sendMessageStream(history: Message[], userInput: string, isCodeTask: boolean = false) {
  // Create a fresh instance right before making an API call to ensure it uses the most up-to-date API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = isCodeTask ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const chat = ai.chats.create({
    model: model,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
      topP: 0.95,
      topK: 40,
    },
  });

  try {
    const result = await chat.sendMessageStream({ message: userInput });

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      // Accessing .text property directly as per guidelines
      yield c.text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Error: Something went wrong with the connection. Please try again.";
  }
}

export async function generateImage(prompt: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Use gemini-2.5-flash-image for default generation
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  // Iterate through parts to find the image data
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image data returned from API.");
}

export async function generateVideo(prompt: string, onProgress: (msg: string) => void): Promise<string> {
  // Using Veo requires a fresh instance for the selected API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  onProgress("Initializing high-performance video synthesis...");
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  onProgress("Rendering cinematic frames... this may take a moment.");
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  onProgress("Finalizing export...");
  const fetchResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await fetchResponse.blob();
  return URL.createObjectURL(blob);
}

export async function transcribeAudio(base64Audio: string, mimeType: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Audio,
              mimeType: mimeType
            }
          },
          {
            text: "Transcribe the spoken content of this audio exactly as it is said. Return only the transcription text and nothing else."
          }
        ]
      }
    });

    // Use .text property
    return response.text?.trim() || "";
  } catch (error) {
    console.error("Transcription Error:", error);
    throw new Error("Failed to transcribe audio.");
  }
}

