        <div className={`flex-shrink-0 h-10 w-10 rounded-2xl flex items-center justify-center text-xl shadow-xl
          ${isUser ? 'bg-[#000080] ml-4' : 'bg-gradient-to-br from-[#FF9933] to-[#FFCC33] mr-4'}`}>
          {isUser ? '👤' : '🇮🇳'}
        </div>

        <div className="flex flex-col space-y-1">
          <div className={`flex items-center gap-2 mb-1 px-1 ${isUser ? 'flex-row-reverse' : ''}`}>
             <span className={`text-[10px] font-black uppercase tracking-[0.2em] opacity-40 ${isUser ? 'text-blue-400' : 'text-orange-400'}`}>
              {isUser ? 'User' : 'AI India Pro'}
            </span>
          </div>
          <div className={`relative px-5 py-4 rounded-3xl shadow-lg border transition-all duration-300
            ${isUser 
              ? 'bg-[#0a0f1e]/80 rounded-tr-none text-slate-100 border-white/5' 
              : 'glass rounded-tl-none text-slate-100 border-white/5'}`}>
            {renderContent()}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatMessage;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import ChatMessage from './components/ChatMessage';
import { Message, Role, ChatSession, MessageType } from './types';
import { sendMessageStream, transcribeAudio, generateImage, generateVideo, editImage } from './services/geminiService';

const themes = [
  { id: 'cosmic', name: 'Cosmic Mesh', icon: '✨' },
  { id: 'grid', name: 'Digital Grid', icon: '🌐' },
  { id: 'golden', name: 'Golden Dawn', icon: '🌅' },
  { id: 'navy', name: 'Deep Navy', icon: '🌑' }
];

const tools = [
  { id: MessageType.TEXT, name: 'Chat', icon: '💬' },
  { id: MessageType.SEARCH, name: 'Search', icon: '🔍' },
  { id: MessageType.IMAGE, name: 'Generate', icon: '🎨' },
  { id: MessageType.EDIT, name: 'Edit Photo', icon: '🪄' },
  { id: MessageType.VIDEO, name: 'Video', icon: '🎬' },
  { id: MessageType.CODE, name: 'Build App', icon: '💻' }
];

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [currentTool, setCurrentTool] = useState<MessageType>(MessageType.TEXT);
  const [isStreaming, setIsStreaming] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [isOnline, setIsOnline] = useState(true);
  const [currentThemeIndex, setCurrentThemeIndex] = useState(0);
  const [videoStatus, setVideoStatus] = useState<string | null>(null);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    const mesh = document.getElementById('mesh');
    if (mesh) mesh.className = `bg-mesh theme-${themes[currentThemeIndex].id}`;
  }, [currentThemeIndex]);

  useEffect(() => {
    if (sessions.length === 0) {
      const newId = Date.now().toString();
      setSessions([{ id: newId, title: 'New Samvaad', messages: [], updatedAt: new Date() }]);
      setCurrentSessionId(newId);
    }
  }, [sessions]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [sessions, isStreaming, videoStatus]);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const handleNewChat = useCallback(() => {
    const newId = Date.now().toString();
    setSessions(prev => [{ id: newId, title: 'New Samvaad', messages: [], updatedAt: new Date() }, ...prev]);
    setCurrentSessionId(newId);
    setUploadedImage(null);
  }, []);

  const handleSelectSession = (id: string) => {
    setCurrentSessionId(id);
    setUploadedImage(null);
  };

  const addMessage = (role: Role, type: MessageType, content: string, metadata?: any) => {
    const newMessage: Message = { id: Date.now().toString(), role, type, content, timestamp: new Date(), metadata };
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, newMessage], updatedAt: new Date() } : s));
    return newMessage.id;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
        if (currentTool !== MessageType.EDIT) setCurrentTool(MessageType.EDIT);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if (!inputValue.trim() || !currentSessionId || isStreaming || !isOnline) return;

    const userText = inputValue.trim();
    const activeTool = currentTool;
    const sourceImg = uploadedImage;

    setInputValue('');
    setUploadedImage(null);
    addMessage(Role.USER, activeTool, userText, sourceImg ? { sourceImage: sourceImg } : undefined);

    if (activeTool === MessageType.TEXT || activeTool === MessageType.SEARCH || activeTool === MessageType.CODE) {
      setIsStreaming(true);
      const modelMessageId = addMessage(Role.MODEL, activeTool, "");
      let accumulatedText = "";
      try {
        const stream = sendMessageStream(currentSession?.messages || [], userText, activeTool === MessageType.SEARCH);
        for await (const chunk of stream) {
          accumulatedText += (chunk as any).text;
          setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
              return { ...s, messages: s.messages.map(m => m.id === modelMessageId ? { 
                ...m, 
                content: accumulatedText,
                metadata: { ...m.metadata, groundingChunks: (chunk as any).grounding }
              } : m) };
            }
            return s;
          }));
        }
      } catch (e) { console.error(e); } finally { setIsStreaming(false); }
    } 
    else if (activeTool === MessageType.IMAGE) {
      setIsStreaming(true);
      try {
        const imageUrl = await generateImage(userText);
        addMessage(Role.MODEL, MessageType.IMAGE, imageUrl, { prompt: userText });
      } catch (e) { addMessage(Role.MODEL, MessageType.TEXT, "Chitra generation failed."); } finally { setIsStreaming(false); }
    } 
    else if (activeTool === MessageType.EDIT) {
      if (!sourceImg) {
        addMessage(Role.MODEL, MessageType.TEXT, "Please upload a photo first to use the Edit tool.");
        return;
      }
      setIsStreaming(true);
      try {
        const editedUrl = await editImage(sourceImg.split(',')[1], userText);
        addMessage(Role.MODEL, MessageType.EDIT, editedUrl, { prompt: userText, sourceImage: sourceImg });
      } catch (e) { addMessage(Role.MODEL, MessageType.TEXT, "Edit failed."); } finally { setIsStreaming(false); }
    }
    else if (activeTool === MessageType.VIDEO) {
      if (!(await window.aistudio.hasSelectedApiKey())) await window.aistudio.openSelectKey();
      setIsStreaming(true);
      try {
        const videoUrl = await generateVideo(userText, setVideoStatus);
        addMessage(Role.MODEL, MessageType.VIDEO, videoUrl, { prompt: userText });
      } catch (e) { addMessage(Role.MODEL, MessageType.TEXT, "Chalchitra synthesis failed."); } finally { setIsStreaming(false); setVideoStatus(null); }
    }
  };

  const toggleRecording = async () => {
    if (isRecording) {
      mediaRecorderRef.current?.stop();
      setIsRecording(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const mr = new MediaRecorder(stream);
        mediaRecorderRef.current = mr;
        audioChunksRef.current = [];
        mr.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
        mr.onstop = async () => {
          const blob = new Blob(audioChunksRef.current, { type: mr.mimeType });
          const base64 = await new Promise<string>(r => {
            const reader = new FileReader();
            reader.onloadend = () => r((reader.result as string).split(',')[1]);
            reader.readAsDataURL(blob);
          });
          setIsTranscribing(true);
          const text = await transcribeAudio(base64, mr.mimeType);
          setInputValue(p => p ? p + ' ' + text : text);
          setIsTranscribing(false);
          stream.getTracks().forEach(t => t.stop());
        };
        mr.start();
        setIsRecording(true);
      } catch (e) { alert("Mic access denied."); }
    }
  };

  return (
    <div className="flex h-screen w-full bg-transparent overflow-hidden text-slate-100 selection:bg-orange-500/20">
      <Sidebar sessions={sessions} currentSessionId={currentSessionId} onSelectSession={handleSelectSession} onNewChat={handleNewChat} />

      <main className="flex-1 flex flex-col relative">
        <header className="h-20 flex items-center justify-between px-8 glass border-b border-white/5 z-20">
          <div className="flex flex-col">
            <span className="text-[9px] font-black uppercase tracking-[0.4em] text-orange-500">Bharat AI Nexus</span>
            <span className="text-sm font-bold tracking-tight text-white/90">{currentSession?.title}</span>
          </div>
          <div className="flex items-center gap-4">
             <button onClick={() => setCurrentThemeIndex(p => (p + 1) % themes.length)} className="px-4 py-2 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all text-xs font-bold flex items-center gap-2">
               <span>{themes[currentThemeIndex].icon}</span>
               <span className="hidden sm:inline">Theme</span>
             </button>
             <div className={`px-4 py-2 rounded-full border text-[10px] font-black uppercase tracking-widest ${isOnline ? 'text-emerald-400 border-emerald-500/20' : 'text-red-400 border-red-500/20'}`}>
                {isOnline ? 'Online' : 'Offline'}
             </div>
          </div>
        </header>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-12 space-y-4 custom-scrollbar">
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-4xl mx-auto py-10">
              <h2 className="text-6xl font-black tracking-tighter text-white mb-6">Namaste, I am <span className="text-gradient-in">AI India</span></h2>
              <p className="text-slate-400 text-xl mb-12 max-w-2xl leading-relaxed">The pinnacle of Bharat's AI evolution. Generate, Edit, Search, and Build with native intelligence.</p>
              <div className="grid grid-cols-2 md:grid-cols-3 gap-4 w-full">
                {tools.map(t => (
                  <button key={t.id} onClick={() => setCurrentTool(t.id)} className={`p-6 rounded-[2rem] border transition-all flex flex-col items-center gap-3 ${currentTool === t.id ? 'bg-orange-500/10 border-orange-500/50 shadow-2xl shadow-orange-500/10' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                    <span className="text-4xl">{t.icon}</span>
                    <span className="text-xs font-black uppercase tracking-widest">{t.name}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="max-w-5xl mx-auto w-full">
              {currentSession?.messages.map((m) => <ChatMessage key={m.id} message={m} />)}
              {(isStreaming || videoStatus) && (
                <div className="flex items-center gap-4 text-[10px] text-orange-400 font-black uppercase tracking-[0.3em] ml-14 py-4 animate-pulse">
                  <span className="w-2 h-2 bg-orange-500 rounded-full"></span>
                  {videoStatus || "Synthesizing Thought..."}
                </div>
              )}
            </div>
          )}
        </div>

        <div className="p-6 md:p-12 pt-0">
          <div className="max-w-5xl mx-auto">
            {uploadedImage && (
              <div className="mb-4 flex items-center gap-4 bg-orange-500/10 p-3 rounded-2xl border border-orange-500/20 animate-in slide-in-from-bottom-2">
                <img src={uploadedImage} className="h-16 w-16 object-cover rounded-xl border border-white/10" alt="Upload" />
                <div className="flex-1">
                  <p className="text-[10px] font-black uppercase tracking-widest text-orange-400">Image Loaded</p>
                  <p className="text-xs text-slate-400">Describe the changes you want to apply...</p>
                </div>
                <button onClick={() => setUploadedImage(null)} className="p-2 hover:bg-white/5 rounded-lg text-slate-500">×</button>
              </div>
            )}

            <div className="flex gap-2 mb-4 overflow-x-auto custom-scrollbar pb-2">
              {tools.map(t => (
                <button key={t.id} onClick={() => setCurrentTool(t.id)} className={`flex-shrink-0 px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${currentTool === t.id ? 'bg-orange-500 text-white shadow-xl shadow-orange-500/20' : 'bg-white/5 text-slate-500 hover:text-slate-300'}`}>
                  {t.icon} {t.name}
                </button>
              ))}
            </div>

            <div className="relative group">
              <div className={`absolute -inset-[2px] bg-gradient-to-r from-orange-500 via-white to-green-600 rounded-[2rem] blur-md opacity-10 group-focus-within:opacity-30 transition duration-700 ${isRecording ? 'opacity-50' : ''}`}></div>
              <div className="relative flex items-center gap-4 glass bg-[#05070a]/90 rounded-[1.8rem] p-3 shadow-2xl border border-white/5">
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                <button onClick={() => fileInputRef.current?.click()} className="p-4 bg-white/5 text-slate-400 hover:text-white rounded-2xl transition-all">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                </button>
                <button onClick={toggleRecording} className={`p-4 rounded-2xl transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-white/5 text-slate-400'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                </button>
                <textarea
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSend())}
                  placeholder={currentTool === MessageType.EDIT ? "What should I change in this photo?" : `Message AI India (${currentTool})...`}
                  rows={1}
                  className="flex-1 bg-transparent border-none focus:ring-0 text-white placeholder-slate-600 resize-none py-4 text-lg font-medium"
                />
                <button onClick={handleSend} disabled={!inputValue.trim() || isStreaming} className={`p-5 w-16 h-16 rounded-2xl transition-all flex items-center justify-center ${inputValue.trim() && !isStreaming ? 'bg-orange-500 text-white shadow-2xl shadow-orange-500/40 hover:scale-[1.05]' : 'bg-white/5 text-slate-700'}`}>
                  {isStreaming ? <div className="animate-spin h-6 w-6 border-2 border-white/20 border-t-white rounded-full"></div> : <svg className="w-8 h-8 rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"/></svg>}
                </button>
              </div>
            </div>
            <p className="text-center text-[8px] text-slate-700 mt-6 font-black uppercase tracking-[0.5em]">Vision 2047 • Next-Gen Digital Bharat</p>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export enum Role {
  USER = 'user',
  MODEL = 'model',
  SYSTEM = 'system'
}

export enum MessageType {
  TEXT = 'text',
  IMAGE = 'image',
  VIDEO = 'video',
  CODE = 'code',
  EDIT = 'edit',
  SEARCH = 'search'
}

export interface User {
  email: string;
  name: string;
  password?: string;
}

export interface Message {
  id: string;
  role: Role;
  type: MessageType;
  content: string; // text or base64/url for media
  timestamp: Date;
  metadata?: {
    prompt?: string;
    status?: 'pending' | 'completed' | 'failed';
    thumbnail?: string;
    sourceImage?: string;
    groundingChunks?: any[];
  };
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: Date;
}

import React, { useState } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const users: User[] = JSON.parse(localStorage.getItem('ai_india_users') || '[]');

    if (isLogin) {
      const user = users.find(u => u.email === email && u.password === password);
      if (user) {
        const { password: _, ...userWithoutPass } = user;
        onLogin(userWithoutPass);
      } else {
        setError('Invalid email or password');
      }
    } else {
      if (users.some(u => u.email === email)) {
        setError('Email already exists');
        return;
      }
      const newUser = { email, password, name };
      users.push(newUser);
      localStorage.setItem('ai_india_users', JSON.stringify(users));
      onLogin({ email, name });
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
      <div className="bg-mesh theme-cosmic absolute inset-0"></div>

      <div className="glass w-full max-w-md p-10 rounded-[2.5rem] border border-white/10 shadow-2xl relative z-10 animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-gradient-to-tr from-orange-500 via-white to-green-600 rounded-3xl mx-auto mb-6 flex items-center justify-center text-4xl shadow-2xl transform hover:rotate-6 transition-transform">
            🇮🇳
          </div>
          <h2 className="text-3xl font-black tracking-tight text-white mb-2">
            {isLogin ? 'Welcome Back' : 'Create Identity'}
          </h2>
          <p className="text-slate-400 text-sm font-medium">Access Bharat's Visionary AI Gateway</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {!isLogin && (
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Full Name</label>
              <input
                type="text"
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full bg-white/5 border border-white/5 focus:border-orange-500/50 focus:ring-0 rounded-2xl p-4 text-white transition-all outline-none placeholder:text-slate-700"
                placeholder="Arjun Sharma"
              />
            </div>
          )}

          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Email Address</label>
            <input
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-white/5 border border-white/5 focus:border-orange-500/50 focus:ring-0 rounded-2xl p-4 text-white transition-all outline-none placeholder:text-slate-700"
              placeholder="arjun@bharat.ai"
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Secure Key</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/5 focus:border-orange-500/50 focus:ring-0 rounded-2xl p-4 text-white transition-all outline-none placeholder:text-slate-700"
              placeholder="••••••••"
            />
          </div>

          {error && <p className="text-red-400 text-[10px] font-bold uppercase tracking-widest text-center animate-pulse">{error}</p>}

          <button
            type="submit"
            className="w-full py-4 bg-orange-500 hover:bg-orange-400 text-white font-black uppercase tracking-widest rounded-2xl transition-all shadow-xl shadow-orange-500/20 active:scale-95"
          >
            {isLogin ? 'Initiate Link' : 'Register Core'}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button
            onClick={() => setIsLogin(!isLogin)}
            className="text-[11px] font-bold text-slate-500 hover:text-white uppercase tracking-widest transition-colors"
          >
            {isLogin ? "New Explorer? Create Account" : "Registered? Identify Yourself"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;

