                  <button key={t.id} onClick={() => setCurrentTool(t.id)} className={`p-5 rounded-2xl border transition-all flex flex-col items-center gap-2 ${currentTool === t.id ? 'bg-orange-50 border-orange-200 shadow-sm' : 'bg-white border-gray-100 hover:border-gray-300'}`}>
                    <span className="text-3xl">{t.icon}</span>
                    <span className="text-[10px] font-bold uppercase tracking-wider text-gray-600">{t.name}</span>
