                <div className="flex-1">
                  <p className="text-[9px] font-bold uppercase text-orange-600">Editing Mode Active</p>
                  <p className="text-[11px] text-gray-600">Enter instructions to modify this photo.</p>
                </div>
                <button onClick={() => setUploadedImage(null)} className="p-1.5 hover:bg-orange-100 rounded-lg text-orange-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                </button>
              </div>
            )}

            <div className="flex gap-1.5 mb-3 overflow-x-auto custom-scrollbar pb-1.5">
              {tools.map(t => (
                <button key={t.id} onClick={() => setCurrentTool(t.id)} className={`flex-shrink-0 px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-wider transition-all ${currentTool === t.id ? 'bg-orange-500 text-white shadow-md shadow-orange-100' : 'bg-white text-gray-500 border border-gray-100 hover:border-gray-200'}`}>
                  {t.icon} {t.name}
